INSERT INTO `analysis_results` VALUES (1,3,'甲醇','中性','文本仅为日报页面标题和导航信息，未提供任何市场分析或走势预测内容。',0.1,'llm',1,'2026-07-06 11:26:43','2026-07-06 11:26:43','2026-07-06 11:26:43'),(2,4,'PTA','中性','文本未提供任何分析内容',0,'llm',1,'2026-07-06 11:26:44','2026-07-06 11:26:44','2026-07-06 11:26:44'),(3,7,'黄金','看涨','从业资格证号：F3033924荡，短期谨慎观望。国债短期震荡反弹，谨慎做多。商品板块来看，黑色短期 投资咨询证号：Z0013026电话：021-68757089 震荡，短期谨慎观望；有色短期震荡回调，短期谨慎观望；能化短期震荡上邮箱：Liuhf@qh168.com.cn 涨，谨慎做多；贵金属短期高位偏强震荡，谨慎做多。刘兵从业资格证号：F03091165从业资格证号：F03089928投资咨询证号：Z0019740电话：021-68757827 【贵金属】周一黄金再破历史新高，沪金主力合约一路上涨突破730 关口，邮箱：wangyil@qh168.com.cn COMEX 黄金6 月合约收至3150 美元一线，贸易紧张局势带来的避险买盘推动黄冯冰金强力上行。2 月核心PCE 同比高于市场预期升至2.8%，为24 年12 月以来新从业资格证号：F3077183短期关注关税政策落地引发的波动，滞胀逻辑下实际利率压制与全球去美元化趋势仍对黄金构成长期支撑，白银则受工业属性拖累走势落后黄金，对黄金维持中长期继续看多思路，若出现一定幅度回调可陆续布局中长线仓位。黑色金属：市场避险情绪增加，钢材期现货价格延续弱势【钢材】周一，国内钢材期现货市场继续延续弱势，市场成交量量低位运行。## Page 2研究所晨会观点精粹间，铁水产量预计会回升至240-245 万吨之间。短期来看，临近月底，又逢清明小长假，钢材市场或继续以区间震荡为主。【铁矿石】周一，铁矿石期现货价格跌幅继续扩大。铁水产量继续延续回升趋势，结合当下钢厂利润水平，铁水产量依然有进一步回升的恐慌。供应方面，本周全球铁矿石发运量环比回升103.1 万吨，同时因前期发货量回落原因，到港量环比回落267 万吨。铁矿石港口库存上周则小幅回升。总体来看，铁矿石价格短期仍以区间震荡为主，走势将跟随钢材价格变化。【硅锰/硅铁】周一，硅锰现货价格持平，硅铁现货价格小幅回落。上周五大品种钢材产量继续回升，铁合金需求尚可。硅锰6517 北方市场价格5850-5900元/吨，南方市场价格5850-5950 元/吨，锰矿现货也延续弱势，天津港南非半短期铁合金价格仍以区间震荡思路对待。能源化工：特朗普威胁打压俄油出口，油价上行【原油】特朗普表示对俄罗斯感到生气，并表示如果俄拒绝与乌克兰停火，他将考虑对俄罗斯石油买家征收二级关税。另外伊朗表示，如果美国威胁转变为实际行动，美国将受到打击，地缘政治风险大幅回升。市场目前在权衡需求风险和供应风险 ，短期制裁导致的供应担忧占据上风，油价小幅上行。【沥青】价格跟随油价小幅回升，但现货涨幅明显有限，基差近期大幅下降。供需两弱局面维持，厂家库存近期保持相对稳定，但库存转移效率放缓，社会库存有一定走高。4 月下游需求恢复情况仍然一般，叠加今年基建投资占比较少，后续资金问题仍然将持续，发货或将继续保持中性水平。近期价格并无明显上行驱动，后期或跟涨原油但幅度有限，保持震荡格局。【PX】外盘价格跟随原油回升至847 美金，PXN 价差回落至201 美金。短期PTA 开工仍然偏低，头部装置检修仍在增加，后期PX 至4 月供需好转情况仍然有限。但近期海外汽油需求增加，调油套利空间转正，后期或仍有季节性走强空间，PX 跟随原油小幅反弹概率仍在。【PTA】PTA 跟随PX 成本走强而上升，幅度不及原料。另外下游开工继续回升，以及4 月检修计划仍有增加，PTA 去库将持续，但近期盘面已经计价，资金持仓近HTTP://WWW.QH168.COM.CN 2 / 6 请务必仔细阅读正文后免责申明## Page 3研究所晨会观点精粹期空单离场明显导致价格小幅反弹。但近期终端产销仍然一般，故主力上行幅度可能有限，短期仍需要关注原油价格变动情况。【乙二醇】乙二醇港口库存再度小幅累库，价格因此受到打压持续保持偏低位国际装置开工近期明显提升，进口预期4 月下到5 月恢复，内地库存维持小幅下降，整体仍在去库进程当中，近月甲醇偏强。随着进口的逐渐恢复，甲醇供应端压力凸显，价格承压，05 合约震荡，09 合约偏空增产能投放推迟，供应端压力预期缓解，库存短期内向下游传导，基本面边际改善，价格预计震荡修复。【LLDPE】PE 下游需求旺季，开工仍在攀升，但上涨幅度缩小，下游订单跟进有限，且高价抑制部分需求，同时供应充足，投产在即，上方压力较大，下方受旺季需求支撑，预计震荡为主，短期可能随原油而企稳，关注新增产能投放情况。高位和进口刚性，需求端也没有爆发式增长的可能，整体平淡，而当前市场主要矛盾是宏观偏弱和铜价下跌，短期偏空。【锡】传原定于4 月1 日召开曼相矿山复工复产交流会被取消，夜盘锡价上涨。缅甸遭受强震，由于缅甸锡矿的重要地位，锡价拉升，但佤邦尚未全面复产，需要一定周期筹备，短期内更可能影响道路运输，鉴于佤邦距离震中较远，预计影游企业采购放缓，三地社会库存继续增加，库存增加934 吨，达到11482 吨。综合来看，周五锡价上涨，更多是情绪推动，实际影响预计有限。目前其他有色金属承压回落，锡将受拖累，若关税导致经济担忧加剧，将承受更大压力，注意风险，但原料供应偏紧，预计将相对坚挺。农产品：美国国内生物燃料政策或达成共识，国际油脂价格上涨【美豆】隔夜市场CBOT 大豆市场收跌，新季种植面积预估和季度库存数据符合市场预期，美国对外贸易紧张关系加剧主导美豆持续疲软。但阶段性受美国贸易关系主导疲软，豆粕成本端支撑略减弱。综合看，豆粕期货空头市场格局暂未改善，上涨驱动不足但破位下行概率也不大，区间震荡行情或【菜粕】国内逐渐进入水产需求旺季，但豆菜粕现货价差收缩，豆粕替代菜粕消费有望增加，菜粕现阶段高库存去化依然缓慢。少1.40 万吨。国内菜粕关税成本限制直接进口骤减，菜籽远期预期到港也不多，压榨产出补充也不足，中期菜粕依然具备驱动上涨的可能。重点关注中加菜系贸易相关政策调整。榈油、菜油三大油脂商业库存总量为198.55 万吨，较上周减少5.97 万吨，跌幅2.92%；同比去年同期上涨20.25 万吨，涨幅11.36%。未来进口大豆到港紧缩状况将逐步改善，阶段性供需转宽预期叠加消费疲软，市场情绪悲观、基差偏弱或将持续。阶段性受国际油脂走强提振反弹，国内菜棕价格溢价支撑稳固，窄幅区间震荡行情或维持。【棕榈油】近月马来西亚棕榈油增产季在即，出口环比持续疲软，棕榈油上涨驱动减弱。上周美国生柴政策预期较前期整理有所改善，2026 开始增加可再生能源掺混抵税政策仍悬而未决。4 月份美豆油受政策不确定影响波动增加，马棕短期超跌叠加相关市场提振反弹较多，但自身基本面趋弱且豆棕依然存在倒挂状态。综合看，棕榈油上涨空间或有限，震荡区间下破或依然需要等待政策明晰且产地HTTP://WWW.QH168.COM.CN 4 / 6 请务必仔细阅读正文后免责申明 4## Page 5好。国内进口菜籽压榨利润丰厚和近月到港受政策不确定影响依然偏少，ICE 菜籽支撑稳定且阶段性反弹也在增加菜籽进口成本，菜油部分受成本驱动下买盘兴趣持续未减。基于未来直接进口的关税成本限制，及未来菜籽进口的不确定影响，油厂及渠道挺价意愿均偏强，短期菜油溢价回落或只能等待政策风险消退了。【生猪】月末集团场出栏节奏略快，大体重猪出栏增多，现货上涨驱动不足，周末现货回调。肥标价差收缩，尽管二育成本下跌，但再补栏表现谨慎。',1,'rule',0,'2026-07-06 11:26:44','2026-07-06 11:26:44','2026-07-06 11:26:44'),(4,2,'PP','中性','文本中未提供明确走势分析',0.2,'llm',1,'2026-07-06 11:26:45','2026-07-06 11:26:45','2026-07-06 11:26:45'),(5,1,'LLDPE','中性','报告标题为L日报，但正文未提供任何价格走势、市场分析或预测信息，无法支撑具体判断。',0.1,'llm',1,'2026-07-06 11:26:45','2026-07-06 11:26:45','2026-07-06 11:26:45'),(6,6,'尿素','中性','报告标题为尿素日报，但正文未提供任何市场分析或价格预测信息，仅包含导航和免责声明。',0.2,'llm',1,'2026-07-06 11:26:46','2026-07-06 11:26:46','2026-07-06 11:26:46'),(7,9,'建材','中性','文本仅为日报目录，未提供具体市场信息或分析依据。',0.2,'llm',1,'2026-07-06 11:26:47','2026-07-06 11:26:47','2026-07-06 11:26:47'),(8,5,'烧碱','中性','文本未提供任何关于烧碱期货走势的分析或数据，仅包含导航和免责申明。',0,'llm',1,'2026-07-06 11:26:4