DROP TABLE IF EXISTS `manual_confirmations`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `manual_confirmations` (
  `id` int NOT NULL AUTO_INCREMENT,
  `article_id` int NOT NULL,
  `original_product` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `original_direction` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `original_reason` text COLLATE utf8mb4_unicode_ci,
  `original_confidence` float DEFAULT NULL,
  `confirmed_product` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `confirmed_direction` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL,
  `confirmed_reason` text COLLATE utf8mb4_unicode_ci,
  `confirmed_confidence` float NOT NULL,
  `confirmed_by` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `note` text COLLATE utf8mb4_unicode_ci,
  `confirmed_at` datetime NOT NULL DEFAULT (now()),
  PRIMARY KEY (`id`),
  KEY `ix_manual_confirmations_article_id` (`article_id`),
  KEY `ix_manual_confirmations_confirmed_at` (`confirmed_at`),
  CONSTRAINT `manual_confirmations_ibfk_1` FOREIGN KEY (`article_id`) REFERENCES `articles` (`id`) ON DELETE CASCADE,
  CONSTRAINT `ck_manual_confirmations_confidence` CHECK (((`confirmed_confidence` >= 0) and (`confirmed_confidence` <= 1))),
  CONSTRAINT `ck_manual_confirmations_direction` CHECK ((`confirmed_direction` in (_utf8mb4'看涨',_utf8mb4'看跌',_utf8mb4'中性')))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
